  }
];

function safeParse<T>(value: string | null, fallback: T): T {
  if (!value) return fallback;
  try {
    return JSON.parse(value) as T;
  } catch {
    return fallback;
  }
}

export function loadPosts(): Post[] {
  if (typeof window === 'undefined') return seedPosts;

  const existing = safeParse<Post[]>(window.localStorage.getItem(POSTS_KEY), []);
  if (existing.length > 0) return existing;

  window.localStorage.setItem(POSTS_KEY, JSON.stringify(seedPosts));
  return seedPosts;
}

export function savePosts(posts: Post[]): void {
  if (typeof window === 'undefined') return;
  window.localStorage.setItem(POSTS_KEY, JSON.stringify(posts));
}

export function loadDraft(): EditorDraft | null {
  if (typeof window === 'undefined') return null;
  return safeParse<EditorDraft | null>(window.localStorage.getItem(DRAFT_KEY), null);
}

export function saveDraft(draft: EditorDraft): void {
  if (typeof window === 'undefined') return;
  window.localStorage.setItem(DRAFT_KEY, JSON.stringify(draft));
}

export function clearDraft(): void {
  if (typeof window === 'undefined') return;
  window.localStorage.removeItem(DRAFT_KEY);
}

import { Role } from '@/lib/types';

type RoleSwitcherProps = {
  role: Role;
  onChange: (role: Role) => void;
};

const roleDescriptions: Record<Role, string> = {
  writer: 'Can draft and schedule posts',
  editor: 'Can draft, publish, and refine content',
  admin: 'Full control: publish, schedule, and analytics governance'
};

export function RoleSwitcher({ role, onChange }: RoleSwitcherProps) {
  const roles: Role[] = ['writer', 'editor', 'admin'];

  return (
    <section className="panel role-panel" aria-label="Role Selection">
      <div>
        <h2 className="panel-title">Workspace Role</h2>
        <p className="panel-subtitle">Switch roles to preview permissions and workflow states.</p>
      </div>

      <div className="role-grid" role="radiogroup" aria-label="Select role">
        {roles.map((value) => {
          const active = value === role;
          return (
            <button
              key={value}
              type="button"
              role="radio"
              aria-checked={active}
              className={`role-chip ${active ? 'active' : ''}`}
              onClick={() => onChange(value)}
            >
              <span className="role-chip-title">{value}</span>
              <span className="role-chip-desc">{roleDescriptions[value]}</span>
            </button>
          );
        })}
      </div>
    </section>
  );
}

import { EditorDraft, SeoAnalysis } from '@/lib/types';

type EditorPanelProps = {
  draft: EditorDraft;
  seo: SeoAnalysis;
  canPublishNow: boolean;
  onChange: (next: EditorDraft) => void;
  onSaveDraftPost: () => void;
  onPublishNow: () => void;
  onSchedule: () => void;
  onSpiceUpIntro: () => void;
  onClear: () => void;
  statusMessage: string;
};

export function EditorPanel({
  draft,
  seo,
  canPublishNow,
  onChange,
  onSaveDraftPost,
  onPublishNow,
  onSchedule,
  onSpiceUpIntro,
  onClear,
  statusMessage
}: EditorPanelProps) {
  const update = <K extends keyof EditorDraft>(key: K, value: EditorDraft[K]) => {
    onChange({ ...draft, [key]: value });
  };

  return (
    <section className="panel">
      <div className="editor-header-row">
        <div>
          <h2 className="panel-title">Creator Studio</h2>
          <p className="panel-subtitle">
            Write like a pro. Entertain like a storyteller. Publish with confidence.
          </p>
        </div>
        <div className={`seo-pill ${seo.score >= 80 ? 'good' : seo.score >= 55 ? 'ok' : 'bad'}`}>
          SEO Score: {seo.score}
        </div>
      </div>

      <div className="editor-grid">
        <label className="field">
          <span>Title</span>
          <input
            value={draft.title}
            onChange={(e) => update('title', e.target.value)}
            placeholder="e.g. The Future of AI Storytelling in Content Marketing"
          />
        </label>

        <label className="field">
          <span>Category</span>
          <input
            value={draft.category}
            onChange={(e) => update('category', e.target.value)}
            placeholder="Writing, Marketing, Tech, Lifestyle..."
          />
        </label>

        <label className="field full">
          <span>Meta Description (120–160 chars)</span>
          <textarea
            value={draft.metaDescription}
            onChange={(e) => update('metaDescription', e.target.value)}
            rows={2}
            placeholder="Summarize your post in a search-friendly way."
          />
        </label>

        <label className="field full">
          <span>Content</span>
          <textarea
            value={draft.content}
            onChange={(e) => update('content', e.target.value)}
            rows={10}
            placeholder="Start writing your entertaining and professional article here..."
          />
        </label>

        <label className="field">
          <span>Tags (comma-separated)</span>
          <input
            value={draft.tagsInput}
            onChange={(e) => update('tagsInput', e.target.value)}
            placeholder="seo, storytelling, content strategy"
          />
        </label>

        <label className="field">
          <span>Schedule for</span>
          <input
            type="datetime-local"
            value={draft.scheduledFor}
            onChange={(e) => update('scheduledFor', e.target.value)}
          />
        </label>
      </div>

      <div className="action-row">
        <button className="btn ghost" type="button" onClick={onSpiceUpIntro}>
          Spice Up Intro ✨
        </button>
        <button className="btn" type="button" onClick={onSaveDraftPost}>
          Save as Draft
        </button>
        <button className="btn warning" type="button" onClick={onSchedule}>
          Schedule Post
        </button>
        <button className="btn success" type="button" disabled={!canPublishNow} onClick={onPublishNow}>
          Publish Now
        </button>
        <button className="btn danger" type="button" onClick={onClear}>
          Clear
        </button>
      </div>

      <div className="status-line" aria-live="polite">
        {statusMessage}
      </div>

      <div className="seo-checks" aria-label="SEO checklist">
        <h3>SEO Checklist</h3>
        <ul>
          <li className={seo.checks.titleLength ? 'pass' : 'fail'}>Title length optimized</li>
          <li className={seo.checks.contentLength ? 'pass' : 'fail'}>Content length is substantial</li>
          <li className={seo.checks.metaDescriptionLength ? 'pass' : 'fail'}>
            Meta description length is ideal
          </li>
          <li className={seo.checks.keywordInTitle ? 'pass' : 'fail'}>Primary keyword in title</li>
          <li className={seo.checks.keywordInContent ? 'pass' : 'fail'}>Primary keyword in content</li>
          <li className={seo.checks.hasTags ? 'pass' : 'fail'}>Multiple tags attached</li>
        </ul>
        {seo.suggestions.length > 0 && (
          <div className="seo-suggestions">
            {seo.suggestions.map((item) => (
              <p key={item}>• {item}</p>
            ))}
          </div>
        )}
      </div>
    </section>
  );
}

import { Post, PostStatus } from '@/lib/types';

type PostListPanelProps = {
  posts: Post[];
  search: string;
  statusFilter: PostStatus | 'all';
  categoryFilter: string;
  onSearchChange: (value: string) => void;
  onStatusFilterChange: (value: PostStatus | 'all') => void;
  onCategoryFilterChange: (value: string) => void;
  onDeletePost: (id: string) => void;
};

function formatDate(date: string): string {
  return new Date(date).toLocaleString([], {
    dateStyle: 'medium',
    timeStyle: 'short'
  });
}

export function PostListPanel({
  posts,
  search,
  statusFilter,
  categoryFilter,
  onSearchChange,
  onStatusFilterChange,
  onCategoryFilterChange,
  onDeletePost
}: PostListPanelProps) {
  return (
    <section className="panel">
      <div className="editor-header-row">
        <div>
          <h2 className="panel-title">Portal Posts</h2>
          <p className="panel-subtitle">Search and moderate your content pipeline.</p>
        </div>
      </div>

      <div className="filters-row">
        <input
          value={search}
          onChange={(e) => onSearchChange(e.target.value)}
          placeholder="Search by title, content, tag..."
        />
        <select value={statusFilter} onChange={(e) => onStatusFilterChange(e.target.value as PostStatus | 'all')}>
          <option value="all">All Statuses</option>
          <option value="draft">Draft</option>
          <option value="scheduled">Scheduled</option>
          <option value="published">Published</option>
        </select>
        <input
          value={categoryFilter}
          onChange={(e) => onCategoryFilterChange(e.target.value)}
          placeholder="Filter category"
        />
      </div>

      <div className="post-list" role="list">
        {posts.length === 0 && <p className="empty-state">No posts match your filters.</p>}

        {posts.map((post) => (
          <article key={post.id} className="post-card" role="listitem">
            <div className="post-card-head">
              <h3>{post.title}</h3>
              <span className={`badge ${post.status}`}>{post.status}</span>
            </div>
            <p>{post.excerpt}</p>
            <div className="meta-row">
              <span>Category: {post.category || 'Uncategorized'}</span>
              <span>SEO: {post.seoScore}</span>
              <span>Views: {post.views.toLocaleString()}</span>
            </div>
            <div className="meta-row">
              <span>Created: {formatDate(post.createdAt)}</span>
              <span>Updated: {formatDate(post.updatedAt)}</span>
              {post.scheduledFor && <span>Scheduled: {formatDate(post.scheduledFor)}</span>}
            </div>
            <div className="tags-row">
              {post.tags.map((tag) => (
                <span key={`${post.id}-${tag}`} className="tag">
                  #{tag}
                </span>
              ))}
            </div>
            <div className="card-actions">
              <button className="btn danger" onClick={() => onDeletePost(post.id)} type="button">
                Delete
              </button>
            </div>
          </article>
        ))}
      </div>
    </section>
  );
}

import { Post } from '@/lib/types';

type AnalyticsPanelProps = {
  posts: Post[];
};

export function AnalyticsPanel({ posts }: AnalyticsPanelProps) {
  const total = posts.length;
  const published = posts.filter((p) => p.status === 'published').length;
  const drafts = posts.filter((p) => p.status === 'draft').length;
  const scheduled = posts.filter((p) => p.status === 'scheduled').length;
  const avgSeo = total ? Math.round(posts.reduce((acc, p) => acc + p.seoScore, 0) / total) : 0;
  const totalViews = posts.reduce((acc, p) => acc + p.views, 0);

  const tags = posts.flatMap((post) => post.tags);
  const tagCounts = tags.reduce<Record<string, number>>((acc, tag) => {
    acc[tag] = (acc[tag] ?? 0) + 1;
    return acc;
  }, {});
  const topTags = Object.entries(tagCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 6);

  const maxTag = topTags[0]?.[1] ?? 1;

  return (
    <section className="panel">
      <div className="editor-header-row">
        <div>
          <h2 className="panel-title">Analytics</h2>
          <p className="panel-subtitle">Editorial health and publishing momentum at a glance.</p>
        </div>
      </div>

      <div className="stats-grid">
        <article className="stat-card">
          <h3>{total}</h3>
          <p>Total Posts</p>
        </article>
        <article className="stat-card">
          <h3>{published}</h3>
          <p>Published</p>
        </article>
        <article className="stat-card">
          <h3>{scheduled}</h3>
          <p>Scheduled</p>
        </article>
        <article className="stat-card">
          <h3>{drafts}</h3>
          <p>Drafts</p>
        </article>
        <article className="stat-card">
          <h3>{avgSeo}</h3>
          <p>Avg SEO Score</p>
        </article>
        <article className="stat-card">
          <h3>{totalViews.toLocaleString()}</h3>
          <p>Total Views</p>
        </article>
      </div>

      <div className="tag-chart">
        <h3>Top Tags</h3>
        {topTags.length === 0 && <p className="empty-state">No tag data yet.</p>}
        {topTags.map(([tag, count]) => (
          <div className="tag-bar-row" key={tag}>
            <span className="tag-label">#{tag}</span>
            <div className="tag-bar-wrap">
              <div className="tag-bar" style={{ width: `${Math.max((count / maxTag) * 100, 6)}%` }} />
            </div>
            <span className="tag-count">{count}</span>
          </div>
        ))}
      </div>
    </section>
  );
}

'use client';

import { useEffect, useMemo, useState } from 'react';
import { AnalyticsPanel } from '@/components/AnalyticsPanel';
import { EditorPanel } from '@/components/EditorPanel';
import { PostListPanel } from '@/components/PostListPanel';
import { RoleSwitcher } from '@/components/RoleSwitcher';
import { analyzeSeo } from '@/lib/seo';
import { clearDraft, loadDraft, loadPosts, saveDraft, savePosts } from '@/lib/storage';
import { EditorDraft, Post, PostStatus, Role } from '@/lib/types';

const defaultDraft: EditorDraft = {
  title: '',
  content: '',
  metaDescription: '',
  category: '',
  tagsInput: '',
  scheduledFor: ''
};

function parseTags(input: string): string[] {
  return input
    .split(',')
    .map((tag) => tag.trim().toLowerCase())
    .filter(Boolean);
}

function makeExcerpt(text: string): string {
  const raw = text.replace(/\s+/g, ' ').trim();
  if (raw.length <= 160) return raw;
  return `${raw.slice(0, 160)}...`;
}

function buildHook(title: string, category: string): string {
  const safeTitle = title.trim() || 'this topic';
  const safeCategory = category.trim() || 'content creation';
  const hooks = [
    `What if everything you knew about ${safeCategory} was only half the story?`,
    `Before we dive in, here is the twist: most people fail at ${safeTitle} for one surprisingly simple reason.`,
    `Confession: I used to overcomplicate ${safeTitle} — until a deadline forced a smarter playbook.`,
    `The internet loves shortcuts, but in ${safeCategory}, one strategic habit beats ten hacks.`
  ];
  return hooks[Math.floor(Math.random() * hooks.length)];
}

export default function HomePage() {
  const [role, setRole] = useState<Role>('writer');
  const [posts, setPosts] = useState<Post[]>([]);
  const [draft, setDraft] = useState<EditorDraft>(defaultDraft);
  const [statusMessage, setStatusMessage] = useState('Autosave enabled. Your draft is protected locally.');

  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState<PostStatus | 'all'>('all');
  const [categoryFilter, setCategoryFilter] = useState('');
  const [activeTab, setActiveTab] = useState<'studio' | 'posts' | 'analytics'>('studio');

  useEffect(() => {
    setPosts(loadPosts());
    const storedDraft = loadDraft();
    if (storedDraft) setDraft(storedDraft);
  }, []);

  useEffect(() => {
    const timeout = window.setTimeout(() => {
      saveDraft(draft);
      setStatusMessage('Draft autosaved.');
    }, 700);

    return () => window.clearTimeout(timeout);
  }, [draft]);

  useEffect(() => {
    const timer = window.setInterval(() => {
      setPosts((prev) => {
        const now = Date.now();
        let changed = false;

        const next = prev.map((post) => {
          if (post.status === 'scheduled' && post.scheduledFor && new Date(post.scheduledFor).getTime() <= now) {
            changed = true;
            return {
              ...post,
              status: 'published',
              updatedAt: new Date().toISOString(),
              views: post.views + Math.floor(Math.random() * 40) + 5
            };
          }
          return post;
        });

        if (changed) {
          savePosts(next);
          setStatusMessage('Scheduled post(s) moved to published.');
        }

        return next;
      });
    }, 30_000);

    return () => window.clearInterval(timer);
  }, []);

  const seo = useMemo(
    () => analyzeSeo(draft.title, draft.content, draft.metaDescription, parseTags(draft.tagsInput)),
    [draft]
  );

  const filteredPosts = useMemo(() => {
    return posts
      .filter((post) => {
        const textMatch =
          search.trim().length === 0 ||
          `${post.title} ${post.content} ${post.tags.join(' ')} ${post.category}`
            .toLowerCase()
            .includes(search.toLowerCase());
        const statusMatch = statusFilter === 'all' || post.status === statusFilter;
        const categoryMatch =
          categoryFilter.trim().length === 0 ||
          post.category.toLowerCase().includes(categoryFilter.toLowerCase());
        return textMatch && statusMatch && categoryMatch;
      })
      .sort((a, b) => +new Date(b.updatedAt) - +new Date(a.updatedAt));
  }, [posts, search, statusFilter, categoryFilter]);

  const resetDraft = () => {
    setDraft(defaultDraft);
    clearDraft();
    setStatusMessage('Editor cleared.');
  };

  const persistPost = (status: PostStatus) => {
    if (!draft.title.trim() || !draft.content.trim()) {
      setStatusMessage('Title and content are required.');
      return;
    }

    if (status === 'scheduled' && !draft.scheduledFor) {
      setStatusMessage('Pick a schedule date/time first.');
      return;
    }

    if (status === 'published' && role === 'writer') {
      setStatusMessage('Writer role cannot publish immediately. Switch to editor/admin.');
      return;
    }

    const tags = parseTags(draft.tagsInput);
    const nowIso = new Date().toISOString();

    const post: Post = {
      id: typeof crypto !== 'undefined' && 'randomUUID' in crypto ? crypto.randomUUID() : String(Date.now()),
      title: draft.title.trim(),
      content: draft.content.trim(),
      metaDescription: draft.metaDescription.trim(),
      excerpt: makeExcerpt(draft.content),
      category: draft.category.trim() || 'General',
      tags,
      status,
      scheduledFor: status === 'scheduled' ? new Date(draft.scheduledFor).toISOString() : null,
      seoScore: seo.score,
      authorRole: role,
      views: status === 'published' ? Math.floor(Math.random() * 100) + 25 : 0,
      createdAt: nowIso,
      updatedAt: nowIso
    };

    const next = [post, ...posts];
    setPosts(next);
    savePosts(next);

    if (status === 'draft') setStatusMessage('Draft post saved to portal.');
    if (status === 'scheduled') setStatusMessage('Post scheduled successfully.');
    if (status === 'published') setStatusMessage('Post published successfully 🎉');

    resetDraft();
  };

  const deletePost = (id: string) => {
    const next = posts.filter((post) => post.id !== id);
    setPosts(next);
    savePosts(next);
    setStatusMessage('Post deleted.');
  };

  const spiceUpIntro = () => {
    const hook = buildHook(draft.title, draft.category);
    const nextContent = draft.content.trim().length > 0 ? `${hook}\n\n${draft.content}` : `${hook}\n\n`;
    setDraft((prev) => ({ ...prev, content: nextContent }));
    setStatusMessage('Intro upgraded with an entertaining hook ✨');
  };

  return (
    <main className="shell">
      <header className="hero">
        <div>
          <p className="eyebrow">Blog Post Portal</p>
          <h1>Professional Publishing. Entertaining Writing. One Smart Workspace.</h1>
          <p>
            Complete MVP + advanced workflow: role-based creation, autosave drafts, SEO scoring, scheduling,
            searchable portal, and analytics.
          </p>
        </div>
      </header>

      <RoleSwitcher role={role} onChange={setRole} />

      <nav className="tabs" aria-label="Portal sections">
        <button className={`tab ${activeTab === 'studio' ? 'active' : ''}`} onClick={() => setActiveTab('studio')}>
          Studio
        </button>
        <button className={`tab ${activeTab === 'posts' ? 'active' : ''}`} onClick={() => setActiveTab('posts')}>
          Posts
        </button>
        <button
          className={`tab ${activeTab === 'analytics' ? 'active' : ''}`}
          onClick={() => setActiveTab('analytics')}
        >
          Analytics
        </button>
      </nav>

      {activeTab === 'studio' && (
        <EditorPanel
          draft={draft}
          seo={seo}
          canPublishNow={role === 'editor' || role === 'admin'}
          onChange={setDraft}
          onSaveDraftPost={() => persistPost('draft')}
          onPublishNow={() => persistPost('published')}
          onSchedule={() => persistPost('scheduled')}
          onSpiceUpIntro={spiceUpIntro}
          onClear={resetDraft}
          statusMessage={statusMessage}
        />
      )}

      {activeTab === 'posts' && (
        <PostListPanel
          posts={filteredPosts}
          search={search}
          statusFilter={statusFilter}
          categoryFilter={categoryFilter}
          onSearchChange={setSearch}
          onStatusFilterChange={setStatusFilter}
          onCategoryFilterChange={setCategoryFilter}
          onDeletePost={deletePost}
        />
      )}

      {activeTab === 'analytics' && <AnalyticsPanel posts={posts} />}
    </main>
  );
}

:root {
  --bg: #070b14;
  --bg-soft: #0f172a;
  --panel: rgba(15, 23, 42, 0.82);
  --panel-border: rgba(148, 163, 184, 0.2);
  --text: #e5ecf9;
  --muted: #9fb0ca;
  --brand: #60a5fa;
  --brand-2: #a78bfa;
  --success: #34d399;
  --warning: #fbbf24;
  --danger: #f87171;
  --radius: 16px;
  --shadow: 0 18px 40px rgba(2, 8, 23, 0.45);
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, sans-serif;
  background: radial-gradient(circle at 10% 10%, #15213f 0%, var(--bg) 44%), var(--bg);
  color: var(--text);
}

.shell {
  max-width: 1120px;
  margin: 0 auto;
  padding: 2rem 1rem 3rem;
}

.hero {
  background: linear-gradient(135deg, rgba(96, 165, 250, 0.2), rgba(167, 139, 250, 0.2));
  border: 1px solid rgba(148, 163, 184, 0.28);
  border-radius: var(--radius);
  padding: 1.5rem;
  box-shadow: var(--shadow);
}

.eyebrow {
  margin: 0;
  color: var(--brand);
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  font-size: 0.78rem;
}

.hero h1 {
  margin: 0.5rem 0;
  line-height: 1.2;
  font-size: clamp(1.6rem, 2vw + 1rem, 2.6rem);
}

.hero p {
  margin: 0;
  color: var(--muted);
}

.panel {
  margin-top: 1rem;
  background: var(--panel);
  border: 1px solid var(--panel-border);
  border-radius: var(--radius);
  padding: 1rem;
  box-shadow: var(--shadow);
  backdrop-filter: blur(10px);
}

.panel-title {
  margin: 0;
  font-size: 1.15rem;
}

.panel-subtitle {
  margin: 0.35rem 0 0;
  color: var(--muted);
}

.role-grid {
  margin-top: 1rem;
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 0.75rem;
}

.role-chip {
  border: 1px solid rgba(148, 163, 184, 0.25);
  background: rgba(15, 23, 42, 0.6);
  color: var(--text);
  border-radius: 12px;
  padding: 0.75rem;
  text-align: left;
  transition: all 0.2s ease;
  cursor: pointer;
}

.role-chip:hover,
.role-chip.active {
  border-color: var(--brand);
  background: rgba(96, 165, 250, 0.12);
}

.role-chip-title {
  display: block;
  text-transform: capitalize;
  font-weight: 700;
}

.role-chip-desc {
  display: block;
  margin-top: 0.25rem;
  color: var(--muted);
  font-size: 0.86rem;
}

.tabs {
  margin-top: 1rem;
  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
}

.tab {
  border: 1px solid rgba(148, 163, 184, 0.22);
  color: var(--text);
  background: rgba(15, 23, 42, 0.55);
  border-radius: 999px;
  padding: 0.45rem 1rem;
  cursor: pointer;
}

.tab.active {
  border-color: var(--brand);
  background: linear-gradient(90deg, rgba(96, 165, 250, 0.25), rgba(167, 139, 250, 0.2));
}

.editor-header-row {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 1rem;
}

.seo-pill {
  border-radius: 999px;
  padding: 0.45rem 0.7rem;
  font-size: 0.85rem;
  border: 1px solid transparent;
}

.seo-pill.good {
  border-color: rgba(52, 211, 153, 0.7);
  background: rgba(52, 211, 153, 0.14);
}

.seo-pill.ok {
  border-color: rgba(251, 191, 36, 0.7);
  background: rgba(251, 191, 36, 0.14);
}

.seo-pill.bad {
  border-color: rgba(248, 113, 113, 0.7);
  background: rgba(248, 113, 113, 0.14);
}

.editor-grid {
  margin-top: 1rem;
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 0.8rem;
}

.field {
  display: flex;
  flex-direction: column;
  gap: 0.4rem;
}

.field span {
  font-size: 0.86rem;
  color: var(--muted);
}

.field input,
.field textarea,
.filters-row input,
.filters-row select {
  width: 100%;
  background: rgba(2, 6, 23, 0.55);
  border: 1px solid rgba(148, 163, 184, 0.25);
  color: var(--text);
  border-radius: 10px;
  padding: 0.62rem 0.74rem;
  font: inherit;
}

.field input:focus,
.field textarea:focus,
.filters-row input:focus,
.filters-row select:focus {
  outline: none;
  border-color: var(--brand);
  box-shadow: 0 0 0 2px rgba(96, 165, 250, 0.2);
}

.field.full {
  grid-column: span 2;
}

.action-row {
  margin-top: 0.95rem;
  display: flex;
  gap: 0.55rem;
  flex-wrap: wrap;
}

.btn {
  border: 1px solid rgba(148, 163, 184, 0.2);
  border-radius: 10px;
  background: rgba(96, 165, 250, 0.18);
  color: var(--text);
  padding: 0.55rem 0.8rem;
  cursor: pointer;
}

.btn:hover {
  transform: translateY(-1px);
}

.btn:disabled {
  opacity: 0.45;
  cursor: not-allowed;
  transform: none;
}

.btn.success {
  background: rgba(52, 211, 153, 0.18);
}

.btn.warning {
  background: rgba(251, 191, 36, 0.18);
}

.btn.danger {
  background: rgba(248, 113, 113, 0.18);
}

.btn.ghost {
  background: rgba(167, 139, 250, 0.18);
}

.status-line {
  margin-top: 0.7rem;
  color: var(--muted);
  font-size: 0.9rem;
}

.seo-checks {
  margin-top: 1rem;
  padding: 0.75rem;
  border-radius: 12px;
  background: rgba(2, 6, 23, 0.45);
  border: 1px solid rgba(148, 163, 184, 0.2);
}

.seo-checks h3 {
  margin: 0;
  font-size: 0.96rem;
}

.seo-checks ul {
  margin: 0.6rem 0 0;
  padding-left: 1.1rem;
}

.seo-checks li {
  margin: 0.25rem 0;
}

.pass {
  color: var(--success);
}

.fail {
  color: var(--danger);
}

.seo-suggestions p {
  margin: 0.35rem 0 0;
  color: var(--muted);
  font-size: 0.88rem;
}

.filters-row {
  margin-top: 0.9rem;
  display: grid;
  grid-template-columns: 1.3fr 0.8fr 0.9fr;
  gap: 0.55rem;
}

.post-list {
  margin-top: 1rem;
  display: grid;
  gap: 0.8rem;
}

.post-card {
  border: 1px solid rgba(148, 163, 184, 0.2);
  border-radius: 12px;
  background: rgba(2, 6, 23, 0.38);
  padding: 0.8rem;
}

.post-card h3 {
  margin: 0;
  font-size: 1rem;
}

.post-card p {
  margin: 0.55rem 0;
  color: var(--muted);
}

.post-card-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 0.8rem;
}

.badge {
  text-transform: capitalize;
  font-size: 0.75rem;
  border-radius: 999px;
  padding: 0.2rem 0.55rem;
  border: 1px solid;
}

.badge.published {
  color: #8cf5c0;
  border-color: rgba(52, 211, 153, 0.5);
}

.badge.scheduled {
  color: #ffd36e;
  border-color: rgba(251, 191, 36, 0.6);
}

.badge.draft {
  color: #a5b4fc;
  border-color: rgba(129, 140, 248, 0.6);
}

.meta-row {
  display: flex;
  gap: 0.6rem;
  flex-wrap: wrap;
  color: var(--muted);
  font-size: 0.82rem;
}

.tags-row {
  margin-top: 0.5rem;
  display: flex;
  flex-wrap: wrap;
  gap: 0.35rem;
}

.tag {
  border-radius: 999px;
  padding: 0.18rem 0.48rem;
  font-size: 0.78rem;
  background: rgba(96, 165, 250, 0.15);
  border: 1px solid rgba(96, 165, 250, 0.35);
}

.card-actions {
  margin-top: 0.6rem;
}

.empty-state {
  color: var(--muted);
}

.stats-grid {
  margin-top: 1rem;
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 0.65rem;
}

.stat-card {
  border: 1px solid rgba(148, 163, 184, 0.2);
  border-radius: 12px;
  background: rgba(2, 6, 23, 0.38);
  padding: 0.8rem;
}

.stat-card h3 {
  margin: 0;
  font-size: 1.45rem;
}

.stat-card p {
  margin: 0.25rem 0 0;
  color: var(--muted);
  font-size: 0.85rem;
}

.tag-chart {
  margin-top: 1rem;
  border: 1px solid rgba(148, 163, 184, 0.2);
  border-radius: 12px;
  padding: 0.9rem;
  background: rgba(2, 6, 23, 0.3);
}

.tag-chart h3 {
  margin: 0 0 0.7rem;
}

.tag-bar-row {
  display: grid;
  grid-template-columns: 130px 1fr 36px;
  align-items: center;
  gap: 0.45rem;
  margin-top: 0.45rem;
}

.tag-label,
.tag-count {
  font-size: 0.82rem;
  color: var(--muted);
}

.tag-bar-wrap {
  height: 10px;
  border-radius: 999px;
  background: rgba(148, 163, 184, 0.15);
  overflow: hidden;
}

.tag-bar {
  height: 100%;
  border-radius: 999px;
  background: linear-gradient(90deg, var(--brand), var(--brand-2));
}

@media (max-width: 900px) {
  .role-grid,
  .stats-grid {
    grid-template-columns: 1fr;
  }

  .editor-grid,
  .filters-row {
    grid-template-columns: 1fr;
  }

  .field.full {
    grid-column: span 1;
  }

  .editor-header-row {
    flex-direction: column;
    align-items: flex-start;
  }

  .tag-bar-row {
    grid-template-columns: 90px 1fr 32px;
  }
}
